// Loop through input items
const output = $input.all().map(item => {
  // Objeto 1 e Objeto 2

  const object1 = $("Busca Cliente").first().json; // Primeiro objeto 
  const object2 = $("Seta Dados").first().json // Segundo objeto
  // Validar que os objetos existem
  if (!object1 || !object2) {
    throw new Error('Os campos "object1" e "object2" são obrigatórios nos dados de entrada.');
  }

  // Misturar os objetos, sobrepondo os valores do segundo objeto, caso não estejam em branco
  const mergedObject = { ...object1 }; // Começa com os valores do objeto 1

  for (const [key, value] of Object.entries(object2)) {
    // Sobrescreve o valor apenas se não estiver vazio
    if (value !== null && value !== undefined && value !== '') {
      mergedObject[key] = value;
    }
  }

  // Retornar o novo objeto combinado
  return { json: { mergedObject } };
});

return output;

